UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('beam-walk', 'Floor tape line, arms out, slow steps.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('single-leg-balance-clock', 'Use 3 directions only: front, side, back. Allow hand support.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('cross-crawl-march', 'Hand to opposite knee, slow tempo.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('skipping-rhythm-drill', 'Skip in place or low skip with claps.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('carioca-walkthrough', 'Walk pattern slowly with verbal count.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('lateral-shuffle-walkthrough', 'Side-step with base-width cue.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('backpedal-walkthrough', 'Slow backward walk with coach clearing space.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('ladder-in-in-out-out', 'Walk the pattern; say the rhythm out loud.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('ladder-ickey-shuffle', 'Walk it without ladder first: floor dots or cones.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.'),
  ('low-hurdle-step-over', 'Use cones or floor lines; step over slowly.', 'No default sex-based adjustment. Scale by balance confidence, coordination, injury history, impact tolerance, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

