-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('beam-walk', 'Beam or line walking narrows the base of support, forcing posture control, visual focus, foot placement, ankle strategy, and trunk organization. TPI junior movement-skill guidance includes low balance beam work and coordination challenges as long-term athletic-development tools.', 'Belongs in Balance / Coordination / Rhythm (narrow_base_balance) — a simple bridge to beam work, single-leg balance, cartwheel line awareness, ninja stepping, and landing balance.', 'Early in Skill when athletes need narrow-base balance before beam skills, single-leg work, or foot-placement drills.', 'Do not rush steps, use raised beams without supervision, or turn line walks into speed challenges. Floor line first; raised beam only when balance is controlled.', 'Scale by beam height, supervision, and balance confidence; use floor tape before elevated surfaces.'),
  ('single-leg-balance-clock', 'Coaching-friendly star-excursion / Y-balance style reaching teaches foot tripod, knee tracking, hip control, pelvic stability, and reach strategy under changing direction — without formal testing intent.', 'Belongs in Balance / Coordination / Rhythm (single_leg_balance_skill) before cutting, plyometrics, and single-leg strength expressions.', 'After foot tripod prep when athletes need single-leg control before landing, cutting, or lower-body skill.', 'Do not turn reaches into max-distance tests or high-volume loaded work — that shifts to Control / Resilience. Reduce reach if stance knee collapses.', 'Scale by reach distance, support, and knee tracking; hypermobility athletes need active arch and knee control.'),
  ('cross-crawl-march', 'Cross-crawl drills practice bilateral coordination, midline crossing, motor planning, balance, and whole-body rhythm — supporting sprint mechanics, crawling, skipping, and many sport patterns.', 'Belongs in Balance / Coordination / Rhythm (cross_body_coordination) as an entry-level contralateral pattern drill.', 'Early coordination block before skipping, marching mechanics, or locomotion skill work.', 'Do not rush tempo until opposite arm-leg pattern is clean. Avoid overclaiming neurological benefits — this is coordination rehearsal.', 'Scale by tempo, knee height, and travel; regress to hand-to-knee in place if pattern breaks.'),
  ('skipping-rhythm-drill', 'Skipping builds rhythm, bounce timing, opposite arm-leg action, posture, and soft landing without max intent — a coordination-rich bridge toward sprint mechanics.', 'Belongs in Balance / Coordination / Rhythm (rhythm_locomotion). Power skips or high-intensity skips shift toward Output.', 'After cross-crawl or A-march when athletes need elastic rhythm before sprint mechanics.', 'Do not turn into power skips, loud contacts, or conditioning. RPE above ~5 suggests Output or Fitness intent.', 'Scale by skip height, distance, and impact tolerance; use marching rhythm if impact is not appropriate.'),
  ('carioca-walkthrough', 'Carioca/grapevine combines lateral travel with cross-front and cross-behind footwork for hip rotation, rhythm, coordination, and lateral movement literacy.', 'Belongs in Balance / Coordination / Rhythm (transverse_coordination). Fast carioca for speed/agility can move toward Output or Fitness.', 'After lateral shuffle mechanics when athletes need crossover sequencing before reactive lateral work.', 'Do not rush before rhythm is clean. Foot tangling means regress to slow walkthrough or side-step progression.', 'Scale by step size, speed, and hip rotation tolerance; hypermobility athletes need knee alignment cues.'),
  ('lateral-shuffle-walkthrough', 'Lateral shuffle teaches side-to-side movement without collapsing base width or posture. Bringing feet too close after push-off reduces stability and raises ankle-inversion risk.', 'Belongs in Balance / Coordination / Rhythm (lateral_movement_skill). Fast shuffle or shuffle-to-sprint may belong in Output or Agility.', 'Before carioca or reactive lateral drills when athletes need base-width and push mechanics.', 'Feet clicking together repeatedly means reduce speed and cue push, not reach. Do not use reactive agility if base width collapses.', 'Scale by depth, speed, and knee tracking; cue active hip and ankle alignment for hypermobility.'),
  ('backpedal-walkthrough', 'Backpedaling develops coordination, mobility, stability, and backward movement confidence while teaching safe defensive footwork and spatial awareness.', 'Belongs in Balance / Coordination / Rhythm (backward_locomotion). Reactive backpedal/break drills belong later.', 'When athletes need backward locomotion before reactive defensive games or backpedal-to-break.', 'Backward locomotion requires a clear lane and safe stopping distance. Do not use in crowded space or before athlete can stop safely.', 'Scale by distance, speed, and supervision; use backward walk with support for older adults.'),
  ('ladder-in-in-out-out', 'The in-in-out-out pattern teaches four-count rhythm and foot sequencing. It trains foot rhythm and agility literacy — it does not replace sprinting, cutting, or reactive agility.', 'Belongs in Balance / Coordination / Rhythm (footwork_rhythm). Long ladder circuits belong in Fitness / Repeatability.', 'After simpler locomotion drills when athletes need foot sequencing before complex ladder patterns.', 'Do not exceed ~4 passes per pattern or use short rest that creates sloppy reps — that is Fitness, not Skill. Classify as footwork rhythm, not reactive agility, without perception cues.', 'Walk the pattern first; use tape boxes or cones when ladder is unavailable.'),
  ('ladder-ickey-shuffle', 'The Ickey Shuffle is a more complex lateral footwork rhythm than basic in-in-out-out, training sequencing, timing, posture, and lead-foot switching at low fatigue.', 'Belongs in Balance / Coordination / Rhythm (footwork_rhythm). Sprint exits shift toward Output.', 'After in-in-out-out when athletes need lateral ladder sequencing.', 'Do not use full speed before pattern is learned. Sprint exits and conditioning circuits belong in Output or Fitness.', 'Walk without ladder first using floor dots or wide cone boxes.'),
  ('low-hurdle-step-over', 'Low hurdle step-overs train hip mobility, posture, rhythm, coordination, and foot clearance in a dynamic but controlled way — foundational before high-speed hurdle hops.', 'Belongs in Balance / Coordination / Rhythm (step_over_coordination). High-speed hurdle hops belong in Output.', 'After A-march or lateral prep when athletes need hip clearance and rhythm before sprint or agility.', 'Lower hurdle height or slow tempo if athlete clips hurdles repeatedly. Do not progress to high-speed hurdle hops without clean step-over control.', 'Use cones or floor markers when hurdles are too high; control hip path for hypermobility.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Balance-cluster validation education (see also skill_movement_intelligence_readiness in 104)
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'skill_balance_readiness',
  NULL,
  'Balance / Coordination / Rhythm without pre-fatigue',
  'Balance, coordination, and rhythm drills should sharpen foot placement, posture, and sequencing at low RPE — not become random fast feet, ladder conditioning circuits, or max-intent agility work in Skill.',
  'Balance cluster cards teach narrow-base balance, single-leg reach, cross-crawl rhythm, skipping, carioca, lateral shuffle, backpedal, ladder footwork, and low hurdle step-overs while athletes are fresh.',
  'Sloppy balance and footwork under fatigue transfer into poor landing, cutting, and defensive movement. Skill phase teaches where the body and feet should go; Output and Fitness express or repeat those patterns under load.',
  'Keep ladder work to ~4 passes per pattern with full rest, cap skipping at moderate rhythm (RPE ≤5), use floor lines before raised beams, require clear lanes for backpedal, and move long ladder circuits or loud fast feet to Fitness or Output.',
  'Do not assign HIIT before balance skill learning, high-volume ladder conditioning, power skips, reactive agility without perception cues, or backpedal in crowded space — reduce dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
